import boto3

def manage_sns_subscriptions():
    """
    Manages SNS subscriptions by accepting user input for endpoints
    and creating subscriptions without validation.
    """
    sns_client = boto3.client('sns')

    topic_arn = input("Enter the SNS Topic ARN (e.g., arn:aws:sns:REGION:ACCOUNT_ID:TOPIC_NAME): ")

    while True:
        endpoint_url = input("Enter the HTTPS endpoint URL for subscription (or 'done' to finish): ")
        if endpoint_url.lower() == 'done':
            break

        if not endpoint_url.strip():
            print("Endpoint URL cannot be empty. Please try again.")
            continue

        try:
            response = sns_client.subscribe(
                TopicArn=topic_arn,
                Protocol='https',
                Endpoint=endpoint_url
            )
            print(f"Subscription initiated successfully for endpoint: {endpoint_url}")
            print(f"Subscription ARN: {response['SubscriptionArn']}")
            print("Please note: The subscription is pending confirmation by the endpoint owner.")
        except Exception as e:
            print(f"Error creating subscription for {endpoint_url}: {e}")

if __name__ == "__main__":
    manage_sns_subscriptions()